import {
  ChangeDetectionStrategy,
  Component,
  OnInit,
  inject,
  signal,
} from '@angular/core';
import { FormsModule } from '@angular/forms';
import { ApiService } from '../core/api.service';
import { AuthUser } from '../core/models';
import { AuthService } from '../core/auth.service';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrl: './admin-settings.component.css',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class AdminSettingsComponent implements OnInit {
  private readonly auth = inject(AuthService);
  private readonly api = inject(ApiService);
  readonly currentUser = this.auth.user;

  saved = signal(false);
  orgName = signal('Cloudline Sales Org');
  defaultCurrency = signal('USD');
  fiscalStart = signal('February');

  members = signal<AuthUser[]>([]);

  async ngOnInit(): Promise<void> {
    try {
      this.members.set(await this.api.listUsers());
    } catch {
      /* 401 handled centrally; otherwise the member list stays empty. */
    }
  }

  save(): void {
    // Org preferences are UI-only settings (no backend persistence procedure).
    this.saved.set(true);
    setTimeout(() => this.saved.set(false), 1800);
  }

  /** Role changes are local only — the backend exposes no role-update procedure. */
  setRole(id: string, role: string): void {
    this.members.update((list) =>
      list.map((m) => (m.id === id ? { ...m, role: role as AuthUser['role'] } : m)),
    );
  }
}
